export function initializeLazyLoading(){const observerOptions={threshold:.1,rootMargin:"50px"};const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting){const section=entry.target;section.classList.add("visible");if(section.id==="how-it-works"){import("./graph-visualization.js").then(mod=>{mod.initializeHowItWorksGraph()}).catch(err=>{console.warn("How-it-works graph failed to load:",err)})}setTimeout(()=>{observer.unobserve(section)},600)}})},observerOptions);document.querySelectorAll(".lazy-section").forEach(section=>{observer.observe(section)});return observer}if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",initializeLazyLoading)}else{initializeLazyLoading()}